mapper.select:
/* wms-ctmaster-strategy-sql-oracle.xml - selectStrategyHd - 전략 헤더 조회  SQL */
	#{GRIDPAGING_ROWNUMTYPE_TOP}
		SELECT	'0' AS CHK
		        ,CTKEY
				,STGHDKEY
			 	,STGHDDESC

			 	,FN_GET_WMS_CTCD_NAME(#{ctkey}, 'STGTYPE', STGTYPE, 'KOR') AS STGTYPE_DESC
			  	,INSERTDATE
			  	,INSERTURKEY
		  		,UPDATEDATE
		  		,UPDATEURKEY						  					  
		  FROM	TWORK_INFO_STG_HD
		  WHERE
  	   						CTKEY = #{ctkey}

			 		AND STGHDKEY = #{stghdkey}


				    AND #{SEARCH_CONDITION}




				ORDER BY #{colName} DESC


				ORDER BY #{colName} ASC



				ORDER BY UPDATEDATE DESC


	#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

	/* wms-ctmaster-strategy-sql-oracle.xml - selectStrategyHdCount - 전략 헤더 건수 조회  SQL */
		SELECT	COUNT(1)  
		  FROM	TWORK_INFO_STG_HD
		  WHERE
    	  	   CTKEY = #{ctkey} 

		 		AND STGHDKEY = #{stghdkey}


			    AND #{SEARCH_CONDITION}

mapper.insert:
/* wms-ctmaster-strategy-sql-oracle.xml - insertTWorkInfoStgHd - 전략 헤더 등록  SQL */	
	INSERT INTO TWORK_INFO_STG_HD
			(
				CTKEY
		       ,STGHDKEY
		       ,STGHDDESC
		       ,STGTYPE
		       ,INSERTDATE
		       ,INSERTURKEY
		       ,UPDATEDATE
		       ,UPDATEURKEY			      	
		    ) 
		    VALUES 
		    (
		    	#{ctkey}
				,#{stghdkey}
				,#{stghddesc}
				,#{stgtype}
				,#{sysdate}
				,#{surkey}
				,#{sysdate}
				,#{surkey}
			)

mapper.update:
 	/* wms-ctmaster-strategy-sql-oracle.xml - updateTWorkInfoStgHd - 전략 헤더 수정  SQL */
 		UPDATE	TWORK_INFO_STG_HD
 		   SET	UPDATEDATE  		= #{sysdate}
		        ,UPDATEURKEY 		= #{surkey}
		        ,STGHDDESC    		= #{stghddesc}
		        ,STGTYPE        	= #{stgtype}
		 WHERE	STGHDKEY 			= #{stghdkey}
		   AND 	CTKEY   	     	= #{ctkey}

mapper.delete:

 	/* wms-ctmaster-strategy-sql-oracle.xml - deleteTWorkInfoStgHd - 전략 헤더 삭제  SQL */
			DELETE 
			 FROM	TWORK_INFO_STG_HD
			WHERE	STGHDKEY = #{stghdkey}
			  AND 	CTKEY  = #{ctkey}

mapper.select:
/* wms-ctmaster-strategy-sql-oracle.xml - selectTWorkInfoStgDtCount - 전략 상세 건수 조회 SQL */
	SELECT	COUNT(1)	
	FROM	TWORK_INFO_STG_DT
	WHERE	STGHDKEY = #{stghdkey}
	AND 	CTKEY 	 = #{ctkey}

	AND		STGKEY	= #{stgkey}


	AND		EXEPRTY	= #{exeprty}


		AND STGTYPE = #{stgtype}

/* wms-ctmaster-strategy-sql-oracle.xml - selectTWorkInfoStgDt - 전략 상세 조회 SQL */ SELECT '0' AS CHK ,CTKEY ,STGHDKEY ,AFTER_STGKEY ,STGKEY ,EXEPRTY ,STGTYPE ,FN_GET_WMS_CTCD_NAME(#{ctkey}, 'STGTYPE', STGTYPE, 'KOR') AS STGTYPE_DESC ,STGDTDESC ,INSERTDATE ,INSERTURKEY ,UPDATEDATE ,UPDATEURKEY FROM TWORK_INFO_STG_DT WHERE STGHDKEY = #{stghdkey} AND CTKEY = #{ctkey}
AND STGKEY = #{stgkey}
AND EXEPRTY = #{exeprty}
AND STGTYPE = #{stgtype}
ORDER BY EXEPRTY ASC

